cy.visit('/sign-in');
cy.wait(3000);
const results = [];
cy.get('input, button, a, form, [class*="form"], [class*="auth"]').then($els => {
  $els.each((i, el) => {
    const $el = Cypress.$(el);
    results.push({
      tag: el.tagName.toLowerCase(),
      cls: ($el.attr('class') || '').substring(0, 100),
      id: $el.attr('id') || '',
      name: $el.attr('name') || '',
      type: $el.attr('type') || '',
      placeholder: $el.attr('placeholder') || '',
      href: $el.attr('href') || '',
      text: ($el.text() || '').trim().substring(0, 80)
    });
  });
}).then(() => {
  cy.writeFile('cypress/fixtures/signin-dom.json', results);
});
cy.screenshot('signin-page');

cy.visit('/sign-in');
cy.wait(2000);
// Look for a sign-up / register link
cy.get('body').then($body => {
  const signupLinks = $body.find('a, button').filter((i, el) => {
    const text = (Cypress.$(el).text() || '').toLowerCase();
    return text.includes('sign up') || text.includes('register') || text.includes('create');
  }).map((i, el) => ({
    tag: el.tagName.toLowerCase(),
    text: (Cypress.$(el).text() || '').trim(),
    href: Cypress.$(el).attr('href') || '',
    cls: Cypress.$(el).attr('class') || ''
  })).get();
  cy.writeFile('cypress/fixtures/signup-links.json', signupLinks);
});
cy.screenshot('signin-page-links');

